import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

/*
 * PHASE-07B FROZEN TURN HOOK INTERFACE
 *
 * A turn always resolves in this order:
 * 1. the player action resolves;
 * 2. every other actor runs exactly once in stable actor-id order;
 * 3. end-of-turn tick hooks run in this fixed order:
 *    damageOverTime -> durations -> hunger -> regen.
 *
 * Later phases register combat/AI/status/hunger/regen behavior through TurnHooks.
 * Do not rename TickHookName values, reorder TICK_HOOK_ORDER, or let hooks call
 * ambient nondeterminism or LLMs. Hooks must return deterministic state/events.
 */

import { bounds, config, type GameConfig } from "../../config/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  createInitialState,
  type EngineLogEvent,
  type EntityId,
  type EntityInstance,
  type GameState,
  type TerminalStatus,
} from "../state/index.js";
import {
  checkActionLegality,
  type PlayerAction,
} from "./actions.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly action_illegal: {
      readonly actionKind: PlayerAction["kind"];
      readonly reason: string;
    };
    readonly action_resolved: {
      readonly actionKind: PlayerAction["kind"];
    };
    readonly actor_turn: {
      readonly actorId: EntityId;
    };
    readonly tick_hook: {
      readonly hook: TickHookName;
    };
    readonly terminal_state: {
      readonly status: Exclude<TerminalStatus, "ACTIVE">;
      readonly reason: string;
    };
  }
}

export { checkActionLegality, getAvailableActions } from "./actions.js";
export type {
  AbortAction,
  ActionLegality,
  ActionTarget,
  AttackAction,
  DescendAction,
  InspectAction,
  MoveAction,
  MoveDirection,
  PickupAction,
  PlayerAction,
  TalkAction,
  UseItemAction,
  WaitAction,
} from "./actions.js";

export type TurnEvent = EngineLogEvent;

export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;

export type TickHookName =
  | "damageOverTime"
  | "durations"
  | "hunger"
  | "regen";

export const TICK_HOOK_ORDER = [
  "damageOverTime",
  "durations",
  "hunger",
  "regen",
] as const satisfies readonly TickHookName[];

export type TurnHookResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type ActorTurnHook = (context: {
  readonly state: GameState;
  readonly actor: ActorEntity;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHook = (context: {
  readonly state: GameState;
  readonly hook: TickHookName;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHooks = {
  readonly [Hook in TickHookName]: TickHook;
};

export type TurnHooks = {
  readonly actorTurn?: ActorTurnHook;
  readonly ticks?: Partial<TickHooks>;
};

export type ResolvedTurnHooks = {
  readonly actorTurn: ActorTurnHook;
  readonly ticks: TickHooks;
};

export type StepOptions = {
  readonly hooks?: TurnHooks;
};

export type StepResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type StartContent = {
  readonly config?: GameConfig;
};

export const start = (seed: string, content: StartContent = {}): GameState =>
  createInitialState(seed, content.config ?? config);

export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  const hooks = resolveTurnHooks(options.hooks);
  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
  ];

  let nextState = state;
  const playerActionResult = applyPlayerAction(nextState, action);
  nextState = playerActionResult.state;
  events.push(...playerActionResult.events);

  if (!isTerminal(nextState)) {
    for (const actor of actorsInTurnOrder(nextState)) {
      events.push(
        turnEvent(nextState.run.turn, "actor_turn", {
          actorId: actor.id,
        }),
      );

      const result = normalizeHookResult(
        hooks.actorTurn({
          state: nextState,
          actor,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    for (const hook of TICK_HOOK_ORDER) {
      events.push(
        turnEvent(nextState.run.turn, "tick_hook", {
          hook,
        }),
      );

      const result = normalizeHookResult(
        hooks.ticks[hook]({
          state: nextState,
          hook,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    nextState = advanceTurn(nextState);

    const terminal = forcedTerminalFor(nextState);
    if (terminal !== null) {
      nextState = withTerminalStatus(nextState, terminal.status);
      events.push(
        turnEvent(nextState.run.turn, "terminal_state", {
          status: terminal.status,
          reason: terminal.reason,
        }),
      );
    }
  }

  nextState = appendLog(nextState, events);

  return {
    state: nextState,
    events,
  };
};

export const render = (state: GameState): string =>
  [
    `run=${state.run.runId}`,
    `turn=${state.run.turn}`,
    `depth=${state.run.depth}`,
    `status=${state.run.terminalStatus}`,
    `player=(${state.player.position.x},${state.player.position.y})`,
    `hp=${state.player.hp.current}/${state.player.hp.max}`,
  ].join(" ");

export const isTerminal = (state: GameState): boolean =>
  state.run.terminalStatus !== ACTIVE_TERMINAL_STATUS;

export const createNoopTurnHooks = (): ResolvedTurnHooks => ({
  actorTurn: ({ state }) => state,
  ticks: {
    damageOverTime: ({ state }) => state,
    durations: ({ state }) => state,
    hunger: ({ state }) => state,
    regen: ({ state }) => state,
  },
});

const applyPlayerAction = (
  state: GameState,
  action: PlayerAction,
): StepResult => {
  if (action.kind === "abort") {
    const status = config.runStructure.terminalStates.abort;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player aborted the run",
        }),
      ],
    };
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= config.runStructure.depthFloors
  ) {
    const status = config.runStructure.terminalStates.win;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player descended from the final floor",
        }),
      ],
    };
  }

  return {
    state,
    events: [],
  };
};

const forcedTerminalFor = (
  state: GameState,
): { readonly status: Exclude<TerminalStatus, "ACTIVE">; readonly reason: string } | null => {
  if (state.player.hp.current <= 0) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: "player HP reached 0",
    };
  }

  if (state.run.turn >= bounds.runStructure.perRunHardCapTurns) {
    return {
      status: config.runStructure.terminalStates.loss,

      status: config.runStructure.terminalStates.loss,
      reason: `run hard cap reached at ${bounds.runStructure.perRunHardCapTurns} turns`,
    };
  }

  return null;
};

const terminalStep = (
  state: GameState,
  status: Exclude<TerminalStatus, "ACTIVE">,
  reason: string,
): StepResult => {
  const event = turnEvent(state.run.turn, "terminal_state", {
    status,
    reason,
  });
  const terminalState = appendLog(withTerminalStatus(state, status), [event]);

  return {
    state: terminalState,
    events: [event],
  };
};

const illegalStep = (
  state: GameState,
  action: PlayerAction,
  reason: string,
): StepResult => ({
  state,
  events: [
    turnEvent(state.run.turn, "action_illegal", {
      actionKind: action.kind,
      reason,
    }),
  ],
});

const resolveTurnHooks = (hooks: TurnHooks | undefined): ResolvedTurnHooks => {
  const noopHooks = createNoopTurnHooks();

  return {
    actorTurn: hooks?.actorTurn ?? noopHooks.actorTurn,
    ticks: {
      ...noopHooks.ticks,
      ...hooks?.ticks,
    },
  };
};

const normalizeHookResult = (
  result: TurnHookResult,
): { readonly state: GameState; readonly events: readonly TurnEvent[] } => {
  if (isHookResultEnvelope(result)) {
    return {
      state: result.state,
      events: result.events ?? [],
    };
  }

  return {
    state: result,
    events: [],
  };
};

const isHookResultEnvelope = (
  result: TurnHookResult,
): result is Extract<TurnHookResult, { readonly state: GameState }> =>
  "state" in result;

const actorsInTurnOrder = (state: GameState): readonly ActorEntity[] =>
  Object.values(state.entities)
    .filter(isActorEntity)
    .sort((a, b) => compareEntityIds(a.id, b.id));

const isActorEntity = (entity: EntityInstance): entity is ActorEntity =>
  entity.kind === "enemy" || entity.kind === "npc";

const compareEntityIds = (a: EntityId, b: EntityId): number => {
  const parsedA = parseEntityId(a);
  const parsedB = parseEntityId(b);
  const kindOrder = parsedA.kind.localeCompare(parsedB.kind);

  return kindOrder === 0 ? parsedA.index - parsedB.index : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

const advanceTurn = (state: GameState): GameState => {
  const clock = createClock(state.run.turn);
  clock.advance();

  return {
    ...state,
    run: {
      ...state.run,
      turn: clock.now(),
    },
  };
};

const withTerminalStatus = (
  state: GameState,
  terminalStatus: Exclude<TerminalStatus, "ACTIVE">,
): GameState => ({
  ...state,
  run: {
    ...state.run,
    terminalStatus,
  },
});

const appendLog = (
  state: GameState,
  events: readonly TurnEvent[],
): GameState => ({
  ...state,
  log: [...state.log, ...events],
});

const turnEvent = (
  turn: number,
  type: TurnEvent["type"],
  data: TurnEvent["data"],
): TurnEvent =>
  ({
    turn,
    type,
    data,
  }) as TurnEvent;

const checkUseItemAction = (
  state: GameState,
  action: UseItemAction,
): ActionLegality => {
  if (
    !state.player.inventory.some(
      (slot) => slot?.itemInstanceId === action.itemId,
    )
  ) {
    return illegal(`item ${action.itemId} is not carried`);
  }

  if (action.target === undefined || action.target.kind === "self") {
    return LEGAL_ACTION;
  }

  if (action.target.kind === "entity") {
    return state.entities[action.target.entityId] === undefined
      ? illegal(`target entity ${action.target.entityId} does not exist`)
      : LEGAL_ACTION;
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.target.cell)
    ? LEGAL_ACTION
    : illegal(
        `target cell (${action.target.cell.x}, ${action.target.cell.y}) is outside the map`,
      );
};

const checkPickupAction = (state: GameState): ActionLegality => {
  if (!state.player.inventory.some((slot) => slot === null)) {
    return illegal("inventory is full");
  }

  return sortedEntities(state).some(
    (entity) =>
      entity.kind === "item" &&
      samePosition(entity.position, state.player.position),
  )
    ? LEGAL_ACTION
    : illegal("there is no item here to pick up");
};

const checkTalkAction = (
  state: GameState,
  action: TalkAction,
): ActionLegality => {
  const npc = state.entities[action.npcId];

  if (npc === undefined) {
    return illegal(`npc ${action.npcId} does not exist`);
  }

  if (npc.kind !== "npc") {
    return illegal(`target ${action.npcId} is not an npc`);
  }

  if (!isAdjacentToPlayer(state, npc.position)) {
    return illegal(`npc ${action.npcId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

const checkDescendAction = (state: GameState): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  if (!inBounds(grid, state.player.position)) {
    return illegal(
      `player position (${state.player.position.x}, ${state.player.position.y}) is outside the map`,
    );
  }

  const tile = getTile(grid, state.player.position);

  return tile.terrain === Terrain.StairsDown
    ? LEGAL_ACTION
    : illegal("player is not standing on stairs down");
};

const checkInspectAction = (
  state: GameState,
  action: InspectAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.cell)
    ? LEGAL_ACTION
    : illegal(`inspect cell (${action.cell.x}, ${action.cell.y}) is outside the map`);
};

const availableInspectActions = (state: GameState): readonly InspectAction[] => {
  const grid = gridFromState(state);

  if (grid === null) {
    return [];
  }

  const actions: InspectAction[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      actions.push({
        kind: "inspect",
        cell: { x, y },
      });
    }
  }

  return actions;
};

const carriedItems = (inventory: readonly InventorySlot[]) =>
  inventory.filter((slot) => slot !== null);

const pushIfLegal = (
  actions: PlayerAction[],
  state: GameState,
  action: PlayerAction,
): void => {
  if (isActionLegal(checkActionLegality(state, action))) {
    actions.push(action);
  }
};

const sortedEntities = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities).sort((a, b) => a.id.localeCompare(b.id));

const isAdjacentToPlayer = (state: GameState, position: Position): boolean =>
  chebyshevDistance(state.player.position, position) <= 1;

const samePosition = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const offsetForDirection = (direction: MoveDirection): Position => {
  const entry = MOVE_DIRECTIONS.find((candidate) => candidate.direction === direction);

  if (entry === undefined) {
    throw new RangeError(`unknown move direction: ${direction}`);
  }

  return entry.offset;
};

const isTileGridRecord = (
  value: SerializableRecord | null,
): value is SerializableRecord => {
  if (value === null) {
    return false;
  }

  const record = value as {
    readonly kind?: unknown;
    readonly width?: unknown;
    readonly height?: unknown;
    readonly tiles?: unknown;
  };

  return (
    record.kind === "tile-grid" &&
    Number.isSafeInteger(record.width) &&
    Number.isSafeInteger(record.height) &&
    Array.isArray(record.tiles)
  );
};

const illegal = (reason: string): IllegalActionResult => ({
  status: "illegal",
  reason,
});

import type { GameConfig } from "../../config/index.js";
import type {
  DepthBand,
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  QuestDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { StatusApplication } from "../../schemas/vocab/index.js";

export type SerializablePrimitive = string | number | boolean | null;

export type SerializableValue =
  | SerializablePrimitive
  | readonly SerializableValue[]
  | { readonly [key: string]: SerializableValue };

export type SerializableRecord = {
  readonly [key: string]: SerializableValue;
};

export const ACTIVE_TERMINAL_STATUS = "ACTIVE" as const;

export type ConfiguredTerminalStatus =
  GameConfig["runStructure"]["terminalStates"][keyof GameConfig["runStructure"]["terminalStates"]];

export type TerminalStatus =
  | typeof ACTIVE_TERMINAL_STATUS
  | ConfiguredTerminalStatus;

export interface VersionStamp {
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: typeof ENGINE_VERSION;
}

export interface RunMeta {
  readonly runId: string;
  readonly seed: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly turn: number;
  readonly terminalStatus: TerminalStatus;
}

export interface Position {
  readonly x: number;
  readonly y: number;
}

export interface FloorGeometrySlot {
  readonly refId: string;
  /*
   * PHASE-07A contract: the map module owns this payload's concrete shape.
   * PHASE-06 only requires a stable, serializable geometry reference by id.
   */
  readonly opaque: SerializableRecord | null;
}

export interface FloorState {
  readonly floorId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly geometry: FloorGeometrySlot;
}

export interface PlayerItemStack {
  readonly itemInstanceId: string;
  readonly definition: ItemDefinition;
  readonly quantity: number;
  readonly identified: boolean;
}

export type InventorySlot = PlayerItemStack | null;

export interface EquipmentState {
  readonly weapon: PlayerItemStack | null;
  readonly armor: PlayerItemStack | null;
  readonly charms: readonly (PlayerItemStack | null)[];
}

export interface PlayerState {
  readonly hp: {
    readonly current: number;
    readonly max: number;
  };
  readonly level: number;
  readonly xp: number;
  readonly fullness: {
    readonly current: number;
    readonly max: number;
  };
  readonly position: Position;
  readonly inventory: readonly InventorySlot[];
  readonly equipment: EquipmentState;
  readonly statuses: readonly StatusApplication[];
}

export type EntityKind = "enemy" | "npc" | "item" | "trap";

export type EntityIdCounters = {
  readonly [Kind in EntityKind]: number;
};

export type EntityId = `${EntityKind}#${number}`;

export interface EntityRuntimeFields {
  readonly id: EntityId;
  readonly position: Position;
  readonly currentHP: number | null;
  readonly statuses: readonly StatusApplication[];
  readonly behaviorRuntime: SerializableRecord;
}

export interface EnemyEntityInstance extends EntityRuntimeFields {
  readonly kind: "enemy";
  readonly definition: EnemyDefinition;
  readonly currentHP: number;
}

export interface NpcEntityInstance extends EntityRuntimeFields {
  readonly kind: "npc";
  readonly definition: NpcDefinition;
  readonly dialogueRuntime: SerializableRecord;
}

export interface GroundItemEntityInstance extends EntityRuntimeFields {
  readonly kind: "item";
  readonly definition: ItemDefinition;
  readonly currentHP: null;
  readonly quantity: number;
  readonly identified: boolean;
}

export interface TrapEntityInstance extends EntityRuntimeFields {
  readonly kind: "trap";
  readonly definition: TrapDefinition;
  readonly currentHP: null;
  readonly armed: boolean;
}

export type EntityInstance =
  | EnemyEntityInstance
  | NpcEntityInstance
  | GroundItemEntityInstance
  | TrapEntityInstance;

export type EntityMap = {
  readonly [id: string]: EntityInstance;
};

export type QuestRuntimeStatus = "available" | "active" | "completed" | "failed";

export interface QuestRuntime {
  readonly definition: QuestDefinition;
  readonly status: QuestRuntimeStatus;
  readonly progress: SerializableRecord;
}

export interface QuestState {
  readonly quests: {
    readonly [id: string]: QuestRuntime;
  };
  readonly activeQuestIds: readonly string[];
  readonly completedQuestIds: readonly string[];
  readonly failedQuestIds: readonly string[];
}

/*
 * Log extension pattern:
 * later engine systems add event types by declaration-merging this interface.
 * The runtime serializer validates the event envelope and serializable data.
 */
export interface EngineLogEventDataByType {
  readonly state_created: {
    readonly runId: string;
    readonly seed: string;
    readonly depth: number;
    readonly band: DepthBand;
  };
  readonly state_serialized: {
    readonly format: "stable-json";
  };
  readonly state_deserialized: {
    readonly format: "stable-json";
  };
}

export type EngineLogEventType = Extract<
  keyof EngineLogEventDataByType,
  string
>;

export type EngineLogEvent = {
  readonly [Type in EngineLogEventType]: {
    readonly turn: number;
    readonly type: Type;
    readonly data: EngineLogEventDataByType[Type];
  };
}[EngineLogEventType];

export interface RngStreamCursor {
  readonly streamId: string;
  readonly seed: string;
  readonly parentStreamId: string | null;
  readonly draws: number;
}

export interface RngState {
  readonly rootSeed: string;
  readonly streams: {
    readonly [streamId: string]: RngStreamCursor;
  };
}

export interface IdState {
  readonly entityCounters: EntityIdCounters;
}

export interface GameState {
  readonly version: VersionStamp;
  readonly run: RunMeta;
  readonly floor: FloorState;
  readonly player: PlayerState;
  readonly entities: EntityMap;
  readonly quests: QuestState;
  readonly log: readonly EngineLogEvent[];
  readonly rng: RngState;
  readonly ids: IdState;
}

export const Terrain = {
  Floor: "floor",
  Wall: "wall",
  Door: "door",
  Water: "water",
  StairsDown: "stairs_down",
  Entrance: "entrance",
} as const;

export type TerrainKind = (typeof Terrain)[keyof typeof Terrain];

export type DoorState = "open" | "closed";

export type Tile = {
  readonly terrain: TerrainKind;
  readonly door: DoorState | null;
};

export const TERRAIN_KINDS = [
  Terrain.Floor,
  Terrain.Wall,
  Terrain.Door,
  Terrain.Water,
  Terrain.StairsDown,
  Terrain.Entrance,
] as const satisfies readonly TerrainKind[];

export const TERRAIN_WALKABLE = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: true,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const TERRAIN_TRANSPARENT = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: false,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const createTile = (
  terrain: TerrainKind,
  door: DoorState | null = null,
): Tile => ({
  terrain,
  door: terrain === Terrain.Door ? (door ?? "closed") : null,
});

export const cloneTile = (tile: Tile): Tile => ({
  terrain: tile.terrain,
  door: tile.terrain === Terrain.Door ? (tile.door ?? "closed") : null,
});

export const isWalkableTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_WALKABLE[terrain];

export const isTransparentTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_TRANSPARENT[terrain];

export const isWalkableTile = (tile: Tile): boolean =>
  TERRAIN_WALKABLE[tile.terrain];

export const isTransparentTile = (tile: Tile): boolean => {
  if (tile.terrain === Terrain.Door) {
    return tile.door === "open";
  }

  return TERRAIN_TRANSPARENT[tile.terrain];
};

import {
  config as defaultConfig,
  type GameConfig,
} from "../../config/index.js";
import type {
  FloorGeometrySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  cloneTile,
  createTile,
  Terrain,
  type TerrainKind,
  type Tile,
} from "./terrain.js";

export type TileGrid = {
  readonly kind: "tile-grid";
  readonly width: number;
  readonly height: number;
  readonly tiles: readonly Tile[];
};

export type MapDepthBand = keyof GameConfig["runStructure"]["floorGeometry"];

export type GridBounds = {
  readonly width: number;
  readonly height: number;
};

export type CreateTileGridOptions = GridBounds & {
  readonly fill?: TerrainKind | Tile;
  readonly tiles?: readonly Tile[];
};

export type CreateGridForBandOptions = {
  readonly config?: GameConfig;
  readonly fill?: TerrainKind | Tile;
};

const NEIGHBOR_OFFSETS_8 = [
  { x: -1, y: -1 },
  { x: 0, y: -1 },
  { x: 1, y: -1 },
  { x: -1, y: 0 },
  { x: 1, y: 0 },
  { x: -1, y: 1 },
  { x: 0, y: 1 },
  { x: 1, y: 1 },
] as const satisfies readonly Position[];

export const createTileGrid = ({
  width,
  height,
  fill = Terrain.Floor,
  tiles,
}: CreateTileGridOptions): TileGrid => {
  assertGridDimensions(width, height);
  const expectedTileCount = width * height;

  if (tiles !== undefined) {
    if (tiles.length !== expectedTileCount) {
      throw new RangeError(
        `tile count must equal width * height (${expectedTileCount})`,
      );
    }

    return {
      kind: "tile-grid",
      width,
      height,
      tiles: tiles.map(cloneTile),
    };
  }

  const fillTile = typeof fill === "string" ? createTile(fill) : cloneTile(fill);

  return {
    kind: "tile-grid",
    width,
    height,
    tiles: Array.from({ length: expectedTileCount }, () => cloneTile(fillTile)),
  };
};

export const createGridForBand = (
  band: MapDepthBand,
  options: CreateGridForBandOptions = {},
): TileGrid => {
  const gameConfig = options.config ?? defaultConfig;
  const geometry = gameConfig.runStructure.floorGeometry[band].grid;

  return createTileGrid({
    width: geometry.width,
    height: geometry.height,
    fill: options.fill,
  });
};

export const createFloorGeometrySlot = (
  refId: string,
  grid: TileGrid,
): FloorGeometrySlot => ({
  refId,
  opaque: grid as unknown as SerializableRecord,
});

export const inBounds = (bounds: GridBounds, position: Position): boolean =>
  Number.isSafeInteger(position.x) &&
  Number.isSafeInteger(position.y) &&
  position.x >= 0 &&
  position.x < bounds.width &&
  position.y >= 0 &&
  position.y < bounds.height;

export const idx = (grid: GridBounds, position: Position): number => {
  if (!inBounds(grid, position)) {
    throw new RangeError(`position (${position.x}, ${position.y}) out of bounds`);
  }

  return position.y * grid.width + position.x;
};

export const coord = (grid: GridBounds, index: number): Position => {
  if (!Number.isSafeInteger(index) || index < 0 || index >= grid.width * grid.height) {
    throw new RangeError(`index ${index} out of bounds`);
  }

  return {
    x: index % grid.width,
    y: Math.floor(index / grid.width),
  };
};

export const getTile = (grid: TileGrid, position: Position): Tile =>
  getTileAtIndex(grid, idx(grid, position));

export const getTileAtIndex = (grid: TileGrid, index: number): Tile => {
  const tile = grid.tiles[index];

  if (tile === undefined) {
    throw new RangeError(`tile index ${index} out of bounds`);
  }

  return tile;
};

export const withTile = (
  grid: TileGrid,
  position: Position,
  tile: Tile,
): TileGrid => {
  const index = idx(grid, position);
  const tiles = grid.tiles.map(cloneTile);
  tiles[index] = cloneTile(tile);

  return createTileGrid({
    width: grid.width,
    height: grid.height,
    tiles,
  });
};

export const neighbors8 = (
  grid: GridBounds,
  position: Position,
): readonly Position[] =>
  NEIGHBOR_OFFSETS_8.map((offset) => ({
    x: position.x + offset.x,
    y: position.y + offset.y,
  })).filter((neighbor) => inBounds(grid, neighbor));

export const line = (start: Position, end: Position): readonly Position[] => {
  assertPosition(start, "start");
  assertPosition(end, "end");

  const cells: Position[] = [];
  let x = start.x;
  let y = start.y;
  const dx = Math.abs(end.x - start.x);
  const sx = start.x < end.x ? 1 : -1;
  const dy = -Math.abs(end.y - start.y);
  const sy = start.y < end.y ? 1 : -1;
  let error = dx + dy;

  while (true) {
    cells.push({ x, y });

    if (x === end.x && y === end.y) {
      return cells;
    }

    const doubledError = 2 * error;

    if (doubledError >= dy) {
      error += dy;
      x += sx;
    }

    if (doubledError <= dx) {
      error += dx;
      y += sy;
    }
  }
};

export const discCells = (
  origin: Position,
  radius: number,
  bounds?: GridBounds,
): readonly Position[] => {
  assertPosition(origin, "origin");
  assertNonNegativeInteger(radius, "radius");

  const cells: Position[] = [];
  const radiusSquared = radius * radius;

  for (let y = origin.y - radius; y <= origin.y + radius; y += 1) {
    for (let x = origin.x - radius; x <= origin.x + radius; x += 1) {
      const position = { x, y };
      const dx = x - origin.x;
      const dy = y - origin.y;

      if (
        dx * dx + dy * dy <= radiusSquared &&
        (bounds === undefined || inBounds(bounds, position))
      ) {
        cells.push(position);
      }
    }
  }

  return cells;
};

export const radiusCells = discCells;

export const chebyshevDistance = (a: Position, b: Position): number =>
  Math.max(Math.abs(a.x - b.x), Math.abs(a.y - b.y));

export const distanceSquared = (a: Position, b: Position): number => {
  const dx = a.x - b.x;
  const dy = a.y - b.y;

  return dx * dx + dy * dy;
};

const assertGridDimensions = (width: number, height: number): void => {
  if (!Number.isSafeInteger(width) || width <= 0) {
    throw new RangeError("width must be a positive safe integer");
  }

  if (!Number.isSafeInteger(height) || height <= 0) {
    throw new RangeError("height must be a positive safe integer");
  }

  if (!Number.isSafeInteger(width * height)) {
    throw new RangeError("width * height must be a safe integer");
  }
};

const assertPosition = (position: Position, name: string): void => {
  if (!Number.isSafeInteger(position.x) || !Number.isSafeInteger(position.y)) {
    throw new RangeError(`${name} must contain safe integer coordinates`);
  }
};

const assertNonNegativeInteger = (value: number, name: string): void => {
  if (!Number.isSafeInteger(value) || value < 0) {
    throw new RangeError(`${name} must be a non-negative safe integer`);
  }
};

