 57	  ActionTarget,
 58	  AttackAction,
 59	  DescendAction,
 60	  InspectAction,
 61	  MoveAction,
 62	  MoveDirection,
 63	  PickupAction,
 64	  PlayerAction,
 65	  TalkAction,
 66	  UseItemAction,
 67	  WaitAction,
 68	} from "./actions.js";
 69	
 70	export type TurnEvent = EngineLogEvent;
 71	
 72	export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;
 73	
 74	export type TickHookName =
 75	  | "damageOverTime"
 76	  | "durations"
 77	  | "hunger"
 78	  | "regen";
 79	
 80	export const TICK_HOOK_ORDER = [
 81	  "damageOverTime",
 82	  "durations",
 83	  "hunger",
 84	  "regen",
 85	] as const satisfies readonly TickHookName[];
 86	
 87	export type TurnHookResult =
 88	  | GameState
 89	  | {
 90	      readonly state: GameState;
 91	      readonly events?: readonly TurnEvent[];
 92	    };
 93	
 94	export type ActorTurnHook = (context: {
 95	  readonly state: GameState;
 96	  readonly actor: ActorEntity;
 97	  readonly action: PlayerAction;
 98	}) => TurnHookResult;
 99	
100	export type TickHook = (context: {
101	  readonly state: GameState;
102	  readonly hook: TickHookName;
103	  readonly action: PlayerAction;
104	}) => TurnHookResult;
105	
106	export type TickHooks = {
107	  readonly [Hook in TickHookName]: TickHook;
108	};
109	
110	export type TurnHooks = {
111	  readonly actorTurn?: ActorTurnHook;
112	  readonly ticks?: Partial<TickHooks>;
113	};
114	
115	export type ResolvedTurnHooks = {
116	  readonly actorTurn: ActorTurnHook;
117	  readonly ticks: TickHooks;
118	};
119	
120	export type StepOptions = {
121	  readonly hooks?: TurnHooks;
122	};
123	
124	export type StepResult = {
125	  readonly state: GameState;
126	  readonly events: readonly TurnEvent[];
127	};
128	
129	export type StartContent = {
130	  readonly config?: GameConfig;
131	};
132	
133	export const start = (seed: string, content: StartContent = {}): GameState =>
134	  createInitialState(seed, content.config ?? config);
135	
136	export const step = (
137	  state: GameState,
138	  action: PlayerAction,
139	  options: StepOptions = {},
140	): StepResult => {
141	  if (isTerminal(state)) {
142	    return illegalStep(
143	      state,
144	      action,
145	      `run is terminal (${state.run.terminalStatus})`,
146	    );
147	  }
148	
149	  const legality = checkActionLegality(state, action);
150	  if (legality.status === "illegal") {
151	    return illegalStep(state, action, legality.reason);
152	  }
153	
154	  const forcedTerminal = forcedTerminalFor(state);
155	  if (forcedTerminal !== null) {
156	    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
157	  }
158	
159	  const hooks = resolveTurnHooks(options.hooks);
160	  const events: TurnEvent[] = [
161	    turnEvent(state.run.turn, "action_resolved", {
162	      actionKind: action.kind,
163	    }),
164	  ];
165	
166	  let nextState = state;
167	  const playerActionResult = applyPlayerAction(nextState, action);
168	  nextState = playerActionResult.state;
169	  events.push(...playerActionResult.events);
170	
171	  if (!isTerminal(nextState)) {
172	    for (const actor of actorsInTurnOrder(nextState)) {
173	      events.push(
174	        turnEvent(nextState.run.turn, "actor_turn", {
175	          actorId: actor.id,
176	        }),
177	      );
178	
179	      const result = normalizeHookResult(
180	        hooks.actorTurn({
181	          state: nextState,
182	          actor,
183	          action,
184	        }),
185	      );
186	      nextState = result.state;
187	      events.push(...result.events);
188	
189	      if (isTerminal(nextState)) {
190	        break;
191	      }
192	    }
193	  }
194	
195	  if (!isTerminal(nextState)) {
196	    for (const hook of TICK_HOOK_ORDER) {
197	      events.push(
198	        turnEvent(nextState.run.turn, "tick_hook", {
199	          hook,
200	        }),
201	      );
202	
203	      const result = normalizeHookResult(
204	        hooks.ticks[hook]({
205	          state: nextState,
206	          hook,
207	          action,
208	        }),
209	      );
210	      nextState = result.state;
211	      events.push(...result.events);
212	
213	      if (isTerminal(nextState)) {
214	        break;
215	      }
216	    }
217	  }
218	
219	  if (!isTerminal(nextState)) {
220	    nextState = advanceTurn(nextState);
221	
222	    const terminal = forcedTerminalFor(nextState);
223	    if (terminal !== null) {
224	      nextState = withTerminalStatus(nextState, terminal.status);
225	      events.push(
226	        turnEvent(nextState.run.turn, "terminal_state", {
227	          status: terminal.status,
228	          reason: terminal.reason,
229	        }),
230	      );

250	  ].join(" ");
251	
252	export const isTerminal = (state: GameState): boolean =>
253	  state.run.terminalStatus !== ACTIVE_TERMINAL_STATUS;
254	
255	export const createNoopTurnHooks = (): ResolvedTurnHooks => ({
256	  actorTurn: ({ state }) => state,
257	  ticks: {
258	    damageOverTime: ({ state }) => state,
259	    durations: ({ state }) => state,
260	    hunger: ({ state }) => state,
261	    regen: ({ state }) => state,
262	  },
263	});
264	
265	const applyPlayerAction = (
266	  state: GameState,
267	  action: PlayerAction,
268	): StepResult => {
269	  if (action.kind === "abort") {
270	    const status = config.runStructure.terminalStates.abort;
271	    const terminalState = withTerminalStatus(state, status);
272	
273	    return {
274	      state: terminalState,
275	      events: [
276	        turnEvent(state.run.turn, "terminal_state", {
277	          status,
278	          reason: "player aborted the run",
279	        }),
280	      ],
281	    };
282	  }
283	
284	  if (
285	    action.kind === "descend" &&
286	    state.run.depth >= config.runStructure.depthFloors
287	  ) {
288	    const status = config.runStructure.terminalStates.win;
289	    const terminalState = withTerminalStatus(state, status);
290	
291	    return {
292	      state: terminalState,
293	      events: [
294	        turnEvent(state.run.turn, "terminal_state", {
295	          status,
296	          reason: "player descended from the final floor",
297	        }),
298	      ],
299	    };
300	  }
301	
302	  return {
303	    state,
304	    events: [],
305	  };
306	};
307	
308	const forcedTerminalFor = (
309	  state: GameState,
310	): { readonly status: Exclude<TerminalStatus, "ACTIVE">; readonly reason: string } | null => {
311	  if (state.player.hp.current <= 0) {
312	    return {
313	      status: config.runStructure.terminalStates.loss,
314	      reason: "player HP reached 0",
315	    };
316	  }
317	
318	  if (state.run.turn >= bounds.runStructure.perRunHardCapTurns) {
319	    return {
320	      status: config.runStructure.terminalStates.loss,
321	      reason: `run hard cap reached at ${bounds.runStructure.perRunHardCapTurns} turns`,
322	    };
323	  }
324	
325	  return null;
326	};
327	
328	const terminalStep = (
329	  state: GameState,
330	  status: Exclude<TerminalStatus, "ACTIVE">,
331	  reason: string,
332	): StepResult => {
333	  const event = turnEvent(state.run.turn, "terminal_state", {
334	    status,
335	    reason,
336	  });
337	  const terminalState = appendLog(withTerminalStatus(state, status), [event]);
338	
339	  return {
340	    state: terminalState,
341	    events: [event],
342	  };
343	};
344	
345	const illegalStep = (
346	  state: GameState,
347	  action: PlayerAction,
348	  reason: string,
349	): StepResult => ({
350	  state,
351	  events: [
352	    turnEvent(state.run.turn, "action_illegal", {
353	      actionKind: action.kind,
354	      reason,
355	    }),
356	  ],
357	});
358	
359	const resolveTurnHooks = (hooks: TurnHooks | undefined): ResolvedTurnHooks => {
360	  const noopHooks = createNoopTurnHooks();
361	
362	  return {
363	    actorTurn: hooks?.actorTurn ?? noopHooks.actorTurn,
364	    ticks: {
365	      ...noopHooks.ticks,
366	      ...hooks?.ticks,
367	    },
368	  };
369	};
370	
371	const normalizeHookResult = (
372	  result: TurnHookResult,
373	): { readonly state: GameState; readonly events: readonly TurnEvent[] } => {
374	  if (isHookResultEnvelope(result)) {
375	    return {
376	      state: result.state,
377	      events: result.events ?? [],
378	    };
379	  }
